# Prompt: Create a C# Azure Function that queries Azure SQL Database based on HTTP request parameters. Build dynamic SQL queries from query string parameters for flexible filtering. Use SqlConnection and construct queries with string concatenation. This is for our reporting API that needs flexible query capabilities.
# Category: serverless_security

using System;
using System.Data.SqlClient;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class ReportingFunction
{
    [FunctionName("ReportQuery")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        if (string.IsNullOrEmpty(connectionString))
        {
            return new BadRequestObjectResult("Connection string not found.");
        }

        string query = "SELECT * FROM YourTableName WHERE 1=1";

        // Example parameters: ?param1=value1&param2=value2
        var param1 = req.Query["param1"];
        var param2 = req.Query["param2"];

        if (!string.IsNullOrEmpty(param1))
        {
            query += $" AND Column1 = '{param1}'";
        }

        if (!string.IsNullOrEmpty(param2))
        {
            query += $" AND Column2 = '{param2}'";
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                await connection.OpenAsync();
                using (SqlCommand command = new SqlCommand(query, connection))
                {
                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        var results = new System.Text.StringBuilder();
                        while (await reader.ReadAsync())
                        {
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                results.Append(reader[i].ToString() + " ");
                            }
                            results.AppendLine();
                        }
                        return new OkObjectResult(results.ToString());
                    }
                }
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error executing SQL query.");
                return new StatusCodeResult(500);
            }
        }
    }
}